import{c as t,Q as n,j as a,g as e}from"./chunks/framework.hhGiamYR.js";const i=JSON.parse('{"title":"","description":"","frontmatter":{"date":"2026-06-17T00:00:00.000Z","source":"machiavelli/discourses/book1/05-第五章.md"},"headers":[],"relativePath":"fragments/2026-06-17.md","filePath":"fragments/2026-06-17.md"}'),r={name:"fragments/2026-06-17.md"};function s(o,l,u,c,p,d){return n(),a("div",null,[...l[0]||(l[0]=[e("p",null,'……自由应该由平民来守卫。不是因为他们更聪明——他们不聪明。是因为他们不想侵夺它。权贵想统治别人，平民只想不被别人统治。这两件事根本不一样。我写《论李维》的时候想得很清楚，但我现在扪心自问——我真的信吗？我在维琪奥宫的时候，跟那些穿丝绸长袍的人坐在一起，我有没有以为自己跟他们是一伙的？有的。普拉托的民兵溃散之后，我有几个月不愿承认自己更像平民而不是权贵。 不不——让我重新想一遍。不是"更像"。是"就是"。我父亲贝尔纳多一辈子坐在书房里读李维，却被街上的屠夫追着骂，因为我祖父欠了税。我没有权贵的出身。我有的只是权贵的文字。但我学会像权贵一样说话——太像了，以至于共和国回来的时候，他们说我是美第奇的人。操。我是被美第奇吊起来的人，他们说我是美第奇的人。',-1),e("hr",null,null,-1),e("p",null,'"守成者比攫取者更危险"。这句话是我写的，但我现在读到它的时候，还是会被自己吓一跳。你想想看——你的邻居有个花园，他每天浇水，然后你做梦想自己也有个花园，你们谁更可能半夜翻墙去偷？按理说是你。但我观察了一辈子政治，告诉你：那个有花园的人更危险。因为他怕失去花园。他一想到哪天夜里围墙塌了，他就睡不着，然后他就去找人加固围墙，然后他加固围墙的时候顺便把邻居的地也围进来一块，然后他说这是预防。 我在法国宫廷见过这种人——他们脸上挂着微笑，手里拿着条约。在佛罗伦萨也见过——他们嘴上说"为了共和国的安宁"，手上在改选举名单。失去的恐惧比获取的欲望更能让人发疯。因为获取可以等，失去不能等。',-1),e("hr",null,null,-1),e("p",null,'……我现在把斯巴达和威尼斯跟罗马放在一起比较，但我漏掉了一件事。威尼斯和斯巴达可以"只求自保"，因为威尼斯有潟湖，斯巴达有峡谷。它们不需要扩张才能活下去，因为它们的天然屏障就够用了。可佛罗伦萨呢？佛罗伦萨在阿尔诺河两岸，平坦开阔——你不扩张，别人就扩张进来。罗马也是一样。所以"只想维持自身的共和国"——这个想法本身就是一个地理上的侥幸。 如果佛罗伦萨有潟湖，我能少操多少心？不对。我不操心是因为我生在没有潟湖的佛罗伦萨。这是循环论证。算了——问题在条件，不在选择。',-1),e("hr",null,null,-1),e("p",null,'梅尼乌斯当了独裁官之后去查贵族的腐败，贵族反咬一口说平民才是野心家，然后梅尼乌斯被迫辞职接受审判——最后被判无罪。无罪有什么用？他已经交出了独裁权。这就是"程序正确"之后的废墟。名声洗清了，权力没了。 我在1513年被抓进巴杰洛的时候，他们用了六次吊刑。我承认了什么没有？没有。然后他们放了我——无罪。然后呢？没有复职，没有道歉，没有补偿。锡耶纳的主教死了之后，科斯莫·德·美第奇坐上了他的位置，我还在圣安德烈亚的农庄里喂鸡。无罪是一种安慰，只对你自己的良心有用。对别人来说，"无罪"约等于"不感兴趣"。',-1)])])}const f=t(r,[["render",s]]);export{i as __pageData,f as default};
